import { existsSync, readFileSync } from 'node:fs';
import { resolve } from 'node:path';

import {
  UNLIMITED_OCR_DEFAULT_PROMPT,
  UNLIMITED_OCR_QSPEC_MAX_TOKENS,
  type UnlimitedOcrProbeSpec,
} from '../src/unlimited-ocr-qspec';
import { runUnlimitedOcrDocument } from '../src/unlimited-ocr-runner';

interface Args {
  qspec: string;
  modelDir: string;
  pdf?: string;
  outDir: string;
  llamaMtmdCli: string;
  skipInference: boolean;
}

function parseArgs(argv: string[]): Args {
  const args: Args = {
    qspec: 'open-source/gnosis/monster-swarm/qspecs/unlimited-ocr.qspec.json',
    modelDir: '/tmp/unlimited-ocr-gguf',
    outDir: '/tmp/unlimited-ocr-qspec',
    llamaMtmdCli: 'llama-mtmd-cli',
    skipInference: false,
  };

  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i];
    const value = argv[i + 1];
    if (arg === '--') {
      continue;
    } else if (arg === '--qspec' && value) {
      args.qspec = value;
      i += 1;
    } else if (arg === '--model-dir' && value) {
      args.modelDir = value;
      i += 1;
    } else if (arg === '--pdf' && value) {
      args.pdf = value;
      i += 1;
    } else if (arg === '--out-dir' && value) {
      args.outDir = value;
      i += 1;
    } else if (arg === '--llama-mtmd-cli' && value) {
      args.llamaMtmdCli = value;
      i += 1;
    } else if (arg === '--skip-inference') {
      args.skipInference = true;
    } else {
      throw new Error(`unknown argument: ${arg}`);
    }
  }

  return args;
}

function readQspec(path: string): UnlimitedOcrProbeSpec {
  const raw = JSON.parse(readFileSync(path, 'utf8')) as Record<string, unknown>;
  const inputPdf =
    typeof (raw.input as Record<string, unknown>)?.pdf === 'string'
      ? String((raw.input as Record<string, unknown>).pdf)
      : undefined;

  return {
    probe: 'unlimited-ocr-gguf',
    model: 'unlimited-ocr',
    modality: 'ocr',
    gate_tier: 'visible-document-ocr',
    artifacts: {
      repoId: String((raw.artifacts as Record<string, unknown>)?.repo_id),
      quant: String((raw.artifacts as Record<string, unknown>)?.quant),
      modelFilename: String((raw.artifacts as Record<string, unknown>)?.model_gguf),
      mmprojFilename: String((raw.artifacts as Record<string, unknown>)?.mmproj_gguf),
      chatTemplate: 'deepseek-ocr',
    },
    prompt: typeof raw.prompt === 'string' ? raw.prompt : UNLIMITED_OCR_DEFAULT_PROMPT,
    input: {
      ...(inputPdf ? { pdf: inputPdf } : {}),
      renderPage: Number((raw.input as Record<string, unknown>)?.render_page ?? 1),
      renderDpi: Number((raw.input as Record<string, unknown>)?.render_dpi ?? 180),
    },
    decode: {
      maxTokens: Number(
        (raw.decode as Record<string, unknown>)?.max_tokens ??
          UNLIMITED_OCR_QSPEC_MAX_TOKENS
      ),
      ignoreEos: (raw.decode as Record<string, unknown>)?.ignore_eos !== false,
    },
    expect: {
      minTextChars: Number((raw.expect as Record<string, unknown>)?.min_text_chars ?? 80),
      requiredTerms: Array.isArray((raw.expect as Record<string, unknown>)?.required_terms)
        ? ((raw.expect as Record<string, unknown>).required_terms as string[])
        : [],
    },
  };
}

async function main(): Promise<void> {
  const args = parseArgs(process.argv.slice(2));
  const qspec = readQspec(args.qspec);
  const pdf = resolve(args.pdf ?? qspec.input.pdf ?? '');
  if (!pdf || !existsSync(pdf)) {
    throw new Error(`PDF not found: ${pdf || '(missing)'}`);
  }

  const result = await runUnlimitedOcrDocument({
    sourcePath: pdf,
    kind: 'pdf',
    prompt: qspec.prompt,
    renderPage: qspec.input.renderPage,
    renderDpi: qspec.input.renderDpi,
    maxTokens: qspec.decode.maxTokens,
    ignoreEos: qspec.decode.ignoreEos,
    requiredTerms: qspec.expect.requiredTerms,
    minTextChars: qspec.expect.minTextChars,
  }, {
    modelDir: args.modelDir,
    outDir: args.outDir,
    llamaMtmdCli: args.llamaMtmdCli,
    skipInference: args.skipInference,
  });

  if (result.inference === 'skipped') {
    console.log(JSON.stringify({ ok: true, rendered: result.imagePath, inference: 'skipped' }, null, 2));
    return;
  }
  if (!result.validation.pass) {
    throw new Error(`Unlimited OCR qspec failed: ${JSON.stringify(result.validation)}`);
  }

  console.log(JSON.stringify({ ok: true, rendered: result.imagePath, output: result.outputPath }, null, 2));
}

void main();
